const pollMs = 100;
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'enderman', 'witch', 'phantom', 'ravager', 'piglin', 'hoglin']);
const findNearestHostile = function () {
  let nearest = null;
  let minDist = Infinity;
  for (const id in bot.entities) {
    const entity = bot.entities[id];
    if (!entity || !entity.isValid || entity.health <= 0) continue;
    const isHostile = entity.kind === 'Hostile mobs' || entity.type === 'hostile' || hostileNames.has(entity.name || '');
    if (isHostile) {
      const dist = bot.entity.position.distanceTo(entity.position);
      if (dist < minDist) {
        minDist = dist;
        nearest = entity;
      }
    }
  }
  return nearest;
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not in a states to kite enemies.';
}
const initialTarget = findNearestHostile();
if (!initialTarget) {
  return '<STOPPED>: No hostiles nearby to kite.';
}
startBackgroundSkill(bot, 'kite_nearest_hostile', async function (token) {
  const startTime = Date.now();
  const movements = new Movements(bot);
  movements.canDig = false;
  movements.allowSprinting = true;
  bot.pathfinder.setMovements(movements);
  try {
    while (canContinueBotAction(bot, token)) {
      const elapsed = Date.now() - startTime;
      if (elapsed >= args.maxDurationMs) break;
      const target = findNearestHostile();
      if (!target) {
        bot.pathfinder.setGoal(null);
        if (!await waitForActiveMs(bot, token, 1000, pollMs)) break;
        continue;
      }
      const dist = bot.entity.position.distanceTo(target.position);
      if (dist < args.preferredDistance) {
        const direction = bot.entity.position.minus(target.position).normalize();
        const retreatPos = bot.entity.position.plus(direction.scaled(args.retreatDistance));
        bot.pathfinder.setGoal(new goals.GoalNear(retreatPos.x, retreatPos.y, retreatPos.z, 1));
      } else if (dist > args.preferredDistance + 5) {
        bot.pathfinder.setGoal(null);
        await bot.lookAt(target.position.offset(0, target.height || 1, 0), true);
      }
      if (!await waitForActiveMs(bot, token, 200, pollMs)) break;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.clearControlStates();
  }
});
